using namespace std;

class Solution {
public:
    int findTheLongestSubstring(string s) {
        unordered_map<int, int> mask_map;
        mask_map[0] = -1;
        int current_mask = 0;
        int max_len = 0;
        int n = s.size();
        for (int i = 0; i < n; ++i) {
            char c = s[i];
            if (c == 'a' || c == 'e' || c == 'i' || c == 'o' || c == 'u') {
                int bit;
                switch(c) {
                    case 'a': bit = 0; break;
                    case 'e': bit = 1; break;
                    case 'i': bit = 2; break;
                    case 'o': bit = 3; break;
                    case 'u': bit = 4; break;
                    default: continue;
                }
                current_mask ^= (1 << bit);
            }
            if (mask_map.find(current_mask) != mask_map.end()) {
                int len = i - mask_map[current_mask];
                if (len > max_len) {
                    max_len = len;
                }
            } else {
                mask_map[current_mask] = i;
            }
        }
        return max_len;
    }
};

